from urllib.parse import urlparse, urljoin, parse_qs

def is_safe_url(target: str, host_url: str) -> bool:
    if not target:
        return False
    ref_url = urlparse(host_url)
    test_url = urlparse(urljoin(host_url, target))
    return (
        test_url.scheme in ("http", "https")
        and ref_url.netloc == test_url.netloc
    )

def get_redirect_target(request_url: str, host_url: str, fallback: str = "/") -> str:
    parsed = urlparse(request_url)
    query_params = parse_qs(parsed.query)
    next_url = query_params.get("next", [None])[0]

    if next_url and is_safe_url(next_url, host_url):
        return next_url

    return fallback

def login_redirect(request_url: str, host_url: str, fallback: str = "/dashboard") -> str:
    return get_redirect_target(request_url, host_url, fallback)

